steps.script:
const cleanArg = (v) => { const t = String(v == null ? '' : v).trim(); return /^\{[a-zA-Z0-9_]+\}$/.test(t) ? '' : t; };
const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
const normalize = (value) => (value || '').replace(/\s+/g, ' ').trim();
const postUrl = cleanArg('{post_url}');
const commentText = cleanArg('{comment_text}');
const preview = commentText.slice(0, 80);
if (!commentText) throw new Error('comment_text is required');
if (commentText.length > 2200) return { post_url: postUrl, comment_text_preview: preview, status: 'over_length', length: commentText.length };
const bodyText = normalize(document.body?.innerText || '');
if (/login|log in|sign up/i.test(document.title) || document.querySelector('input[name="username"], input[name="enc_password"]')) return { post_url: postUrl, comment_text_preview: preview, status: 'login_required', url: location.href };
if (/sorry, this page isn't available|page isn't available|user not found/i.test(bodyText)) return { post_url: postUrl, comment_text_preview: preview, status: 'not_found', url: location.href };
const article = document.querySelector('article') || document.querySelector('main');
let composer = article?.querySelector("textarea[aria-label^='Add a comment'], textarea[placeholder^='Add a comment']") || document.querySelector("textarea[aria-label^='Add a comment'], textarea[placeholder^='Add a comment']");
if (!composer) {
  const toggle = Array.from((article || document).querySelectorAll('span, div, button, [role="button"]')).find((node) => /^add a comment/i.test(normalize(node.textContent || '')));
  if (toggle) { toggle.click(); await sleep(500); composer = article?.querySelector("textarea[aria-label^='Add a comment'], textarea[placeholder^='Add a comment']") || document.querySelector("textarea[aria-label^='Add a comment'], textarea[placeholder^='Add a comment']"); }
}
if (!composer) return { post_url: postUrl, comment_text_preview: preview, status: 'composer_not_found', url: location.href };
composer.focus();
const valueSetter = Object.getOwnPropertyDescriptor(HTMLTextAreaElement.prototype, 'value').set;
valueSetter.call(composer, '');
composer.dispatchEvent(new InputEvent('input', { bubbles: true, composed: true, data: null, inputType: 'deleteContentBackward' }));
await sleep(120);
let typed = '';
for (const ch of commentText) {
  typed += ch;
  composer.dispatchEvent(new KeyboardEvent('keydown', { key: ch, bubbles: true }));
  valueSetter.call(composer, typed);
  composer.dispatchEvent(new InputEvent('input', { bubbles: true, composed: true, data: ch, inputType: 'insertText' }));
  composer.dispatchEvent(new KeyboardEvent('keyup', { key: ch, bubbles: true }));
  if (typed.length % 40 === 0) await sleep(25);
}
composer.dispatchEvent(new Event('change', { bubbles: true }));
await sleep(600);
const isVisible = (node) => { if (!(node instanceof Element)) return false; const rect = node.getBoundingClientRect(); if (rect.width <= 0 || rect.height <= 0) return false; const style = window.getComputedStyle(node); return style.display !== 'none' && style.visibility !== 'hidden' && style.opacity !== '0'; };
const form = composer.closest('form') || article;
const submitCandidates = Array.from((form || article || document).querySelectorAll('button, [role="button"]')).filter(isVisible).filter((node) => /^(post|share)$/i.test(normalize(node.textContent || '')));
const submit = submitCandidates.find((node) => !(node.getAttribute('aria-disabled') === 'true' || node.disabled)) || submitCandidates[0];
if (!submit) return { post_url: postUrl, comment_text_preview: preview, status: 'submit_button_not_found', url: location.href };
if (submit.getAttribute('aria-disabled') === 'true' || submit.disabled) return { post_url: postUrl, comment_text_preview: preview, status: 'submit_disabled', submit_label: normalize(submit.textContent || ''), url: location.href };
submit.scrollIntoView({ block: 'center', inline: 'center' });
try { submit.focus?.({ preventScroll: true }); } catch {}
try { submit.click(); } catch {}
for (const type of ['pointerdown','mousedown','pointerup','mouseup','click']) {
  try {
    const Ctor = type.startsWith('pointer') && typeof PointerEvent !== 'undefined' ? PointerEvent : MouseEvent;
    submit.dispatchEvent(new Ctor(type, { bubbles: true, cancelable: true, composed: true, view: window, button: 0, buttons: 1, pointerType: 'mouse' }));
  } catch {}
}
await sleep(1500);
const composerAfter = document.querySelector("textarea[aria-label^='Add a comment'], textarea[placeholder^='Add a comment']");
const cleared = !composerAfter || !composerAfter.value;
if (cleared) return { post_url: postUrl, comment_text_preview: preview, status: 'posted', submit_click: true, submit_label: normalize(submit.textContent || ''), url: location.href };
return { post_url: postUrl, comment_text_preview: preview, status: 'click_failed', submit_click: true, submit_label: normalize(submit.textContent || ''), composer_value_after: composerAfter?.value?.slice(0, 80), url: location.href };
